#!/bin/bash
set -e
cd ~/chaos_tester

echo "=== Deploy v5: Fix logos (data URIs) + location sanitization ==="

# Step 1: Write patched ai_visibility.py
echo "Step 1: Writing modules/ai_visibility.py..."
echo "" | base64 -d > modules/ai_visibility.py
echo "  Written $(wc -c < modules/ai_visibility.py) bytes"
python3 -c "import ast; ast.parse(open('modules/ai_visibility.py').read()); print('  Syntax: VALID')"

# Step 2: Commit and push
echo "Step 2: Committing and deploying..."
git add modules/ai_visibility.py
git commit -m "fix: use inline SVG data URIs for logos, sanitize location field"
git push origin main

# Step 3: Deploy to Cloud Run
echo "Step 3: Deploying to Cloud Run..."
gcloud run deploy chaos-tester --source . --region us-central1 --project chaos-tester --allow-unauthenticated

echo ""
echo "=== Deploy complete! ==="
echo "Test: https://website-auditor.io"
